test('disables the submit button while submitting', async ({ page }) => {
  // Latch holds the fetch open until we release it, avoiding timing races.
  // The finally block ensures release() is always called so the handler
  // never hangs past the assertion (which caused the 30s test timeout).
  let release!: () => void;
  const latch = new Promise<void>(r => { release = r; });

  await page.route('https://api.web3forms.com/submit', async (route) => {
    await latch;
    await route.fulfill({ json: { success: true } });
  });

  await page.getByLabel('First Name').fill('Jane');
  await page.getByLabel('Last Name').fill('Doe');
  await page.getByLabel('Reason For Message').fill('Hello');
  await page.getByRole('button', { name: 'Submit' }).click();

  const btn = page.locator('button[type="submit"]');
  try {
    await expect(btn).toBeDisabled();
    await expect(btn).toHaveText('Sending...');
  } finally {
    release();
  }
});

