test('disables the submit button while submitting', async ({ page }) => {
  // Patch window.fetch in the browser rather than using page.route().
  // Async page.route() handlers cause a deadlock: click() waits for pending
  // route handlers to settle, but the handler waits for release() which lives
  // after click() — neither can proceed. A browser-side patch has no interaction
  // with Playwright's route system so there's nothing to deadlock on.
  await page.evaluate(() => {
    let resolve: () => void;
    const gate = new Promise<void>(r => { resolve = r; });
    (window as any).__releaseSubmit = () => resolve();
    const orig = window.fetch.bind(window);
    window.fetch = (input, init) => {
      if (String(input).includes('web3forms.com')) {
        return gate.then(() =>
          new Response(JSON.stringify({ success: true }), {
            headers: { 'Content-Type': 'application/json' },
          })
        );
      }
      return orig(input, init);
    };
  });

  await page.getByLabel('First Name').fill('Jane');
  await page.getByLabel('Last Name').fill('Doe');
  await page.getByLabel('Reason For Message').fill('Hello');
  await page.getByRole('button', { name: 'Submit' }).click();

  const btn = page.locator('button[type="submit"]');
  await expect(btn).toBeDisabled();
  await expect(btn).toHaveText('Sending...');

  await page.evaluate(() => (window as any).__releaseSubmit());
});

